namespace sv_4d182a535f394f9bac59764d635ac4f5.Services;

/// <summary>
/// Scoped service that polls for low-stock alerts and notifies all subscribers.
/// Scoped lifetime ensures each user circuit gets independent state.
/// </summary>
public class InventoryAlertService : IDisposable
{
    private readonly Random _random = new();
    private Timer? _timer;
    private int _subscriberCount;
    private string _currentWarehouseId = "WH-001";

    public int LowStockCount { get; private set; }

    /// <summary>
    /// Fired when new alert data arrives. Subscribers must wrap StateHasChanged
    /// in InvokeAsync since this fires from a timer thread.
    /// </summary>
    public event Action? OnAlertDataChanged;

    /// <summary>
    /// Simulates a database query returning the count of items below minimum stock levels.
    /// </summary>
    public Task<int> GetLowStockCountAsync(string warehouseId)
    {
        return Task.FromResult(_random.Next(0, 16));
    }

    public void SetWarehouse(string warehouseId)
    {
        _currentWarehouseId = warehouseId;
        // Immediately poll for the new warehouse
        if (_timer is not null)
        {
            _ = PollAsync();
        }
    }

    public void StartPolling()
    {
        _subscriberCount++;
        if (_timer is null)
        {
            _timer = new Timer(_ => _ = PollAsync(), null, TimeSpan.Zero, TimeSpan.FromSeconds(10));
        }
    }

    public void StopPolling()
    {
        _subscriberCount = Math.Max(0, _subscriberCount - 1);
        if (_subscriberCount == 0)
        {
            _timer?.Dispose();
            _timer = null;
        }
    }

    private async Task PollAsync()
    {
        LowStockCount = await GetLowStockCountAsync(_currentWarehouseId);
        OnAlertDataChanged?.Invoke();
    }

    public void Dispose()
    {
        _timer?.Dispose();
        _timer = null;
    }
}

