@rendermode InteractiveServer
@inject Services.WarehouseState WarehouseState
@inject Services.InventoryAlertService AlertService
@implements IDisposable

<select class="form-select form-select-sm" style="width: 200px;"
        value="@WarehouseState.SelectedWarehouseId"
        @onchange="OnWarehouseChanged">
    @foreach (var wh in Services.WarehouseState.AvailableWarehouses)
    {
        <option value="@wh.Id">@wh.Name</option>
    }
</select>

@code {
    private Action? _handler;

    protected override void OnInitialized()
    {
        _handler = () => InvokeAsync(StateHasChanged);
        WarehouseState.OnChange += _handler;
    }

    private void OnWarehouseChanged(ChangeEventArgs e)
    {
        var warehouseId = e.Value?.ToString() ?? "";
        WarehouseState.SetWarehouse(warehouseId);
        AlertService.SetWarehouse(warehouseId);
    }

    public void Dispose()
    {
        WarehouseState.OnChange -= _handler;
    }
}

@rendermode InteractiveServer
@inject Services.InventoryAlertService AlertService
@implements IDisposable

<span class="badge bg-danger rounded-pill ms-2">@AlertService.LowStockCount</span>

@code {
    private Action? _handler;

    protected override void OnInitialized()
    {
        _handler = () => InvokeAsync(StateHasChanged);
        AlertService.OnAlertDataChanged += _handler;
    }

    public void Dispose()
    {
        AlertService.OnAlertDataChanged -= _handler;
    }
}

@page "/dashboard"
@rendermode InteractiveServer
@inject Services.WarehouseState WarehouseState
@inject Services.InventoryAlertService AlertService
@implements IDisposable

<PageTitle>Dashboard - @WarehouseState.SelectedWarehouseName</PageTitle>

<h1>Warehouse Dashboard</h1>

<div class="row mt-4">
    <div class="col-md-4">
        <div class="card">
            <div class="card-body text-center">
                <h5 class="card-title">Current Warehouse</h5>
                <p class="card-text fs-4">@WarehouseState.SelectedWarehouseName</p>
                <small class="text-muted">@WarehouseState.SelectedWarehouseId</small>
            </div>
        </div>
    </div>
    <div class="col-md-4">
        <div class="card @(AlertService.LowStockCount > 5 ? "border-danger" : "border-success")">
            <div class="card-body text-center">
                <h5 class="card-title">Low Stock Alerts</h5>
                <p class="card-text fs-1 @(AlertService.LowStockCount > 5 ? "text-danger" : "text-success")">
                    @AlertService.LowStockCount
                </p>
                <small class="text-muted">Items below minimum level</small>
            </div>
        </div>
    </div>
    <div class="col-md-4">
        <div class="card">
            <div class="card-body text-center">
                <h5 class="card-title">Polling Status</h5>
                <p class="card-text fs-4 text-success">● Active</p>
                <small class="text-muted">Refreshing every 10 seconds</small>
            </div>
        </div>
    </div>
</div>

@code {
    private Action? _alertHandler;
    private Action? _warehouseHandler;

    protected override void OnInitialized()
    {
        _alertHandler = () => InvokeAsync(StateHasChanged);
        _warehouseHandler = () => InvokeAsync(StateHasChanged);

        AlertService.OnAlertDataChanged += _alertHandler;
        WarehouseState.OnChange += _warehouseHandler;

        // Start polling when dashboard is visible
        AlertService.StartPolling();
    }

    public void Dispose()
    {
        // Stop polling when user leaves the page
        AlertService.StopPolling();
        AlertService.OnAlertDataChanged -= _alertHandler;
        WarehouseState.OnChange -= _warehouseHandler;
    }
}

